import React from 'react';
import { useNavigate } from 'react-router-dom';
import { resolveBrandName, formatRent, safeFloat } from '../../../utils/formatters';

const LeaseExpirySection = ({ leases = [], loading }) => {
  const navigate = useNavigate();

  const handleUnitClick = (unitId) => {
    if (unitId) navigate(`/admin/view-unit/${unitId}`);
  };

  const handleLeaseClick = (leaseId) => {
    navigate(`/admin/view-lease/${leaseId}`);
  };
  // Color coding based on days until expiry
  // Red: <= 30 days (Critical), Blue: 30-90 days (Secure), Green: > 90 days (Active)
  const getExpiryColor = (days) => {
    if (days <= 30) return { bg: '#fee2e2', text: '#991b1b', status: 'Critical' };
    if (days <= 90) return { bg: '#dbeafe', text: '#1d4ed8', status: 'Secure' };
    return { bg: '#dcfce7', text: '#166534', status: 'Active' };
  };

  // Process real lease data
  const processLeases = (leaseData) => {
    if (!leaseData || leaseData.length === 0) return [];

      const now = new Date();

    const processed = leaseData
      .filter(lease => {
        // Include all active/approved/executed/registered leases (status as stored in DB)
        const status = (lease.status || '').toLowerCase().trim();
        const isActive = status === 'active' || status === 'approved' || status === 'executed' || status === 'registered' || status === 'occupied';
        const hasEndDate = !!(lease.lease_end || lease.lease_end_date || lease.endDate);
        return isActive && hasEndDate;
      })
      .map(lease => {
        const expiryDate = new Date(lease.lease_end || lease.lease_end_date || lease.endDate);
        const diffTime = expiryDate - now;
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

        // Resolve unit number from all possible field paths
        const unitNumber = lease.unit_number ||
          (lease.units && !Array.isArray(lease.units) ? lease.units.unit_number : null) ||
          (Array.isArray(lease.units) ? lease.units[0]?.unit_number : null) || '';
        const unitId = lease.unit_id;
        const displayUnit = unitNumber || `#${lease.id}`;

        // Resolve area from all possible paths
        const areaValue = safeFloat(lease.area_leased ||
          (lease.units && !Array.isArray(lease.units) ? lease.units.chargeable_area : null) ||
          (Array.isArray(lease.units) ? lease.units[0]?.chargeable_area : null) || 0);
        const rentAmount = safeFloat(lease.monthly_rent || 0);

        // Use the central resolveBrandName utility — never shows N/A or Lease #ID
        const brandName = resolveBrandName({ ...lease, unit_number: displayUnit });

        return {
          leaseId: lease.id,
          unitId,
          unitNumber: displayUnit,
          brandName,
          area: areaValue > 0 ? `${areaValue.toLocaleString('en-IN')} sqft` : '—',
          amount: formatRent(rentAmount),
          days: diffDays,
          expiryDate
        };
      })
      .filter(l => l.days > 0)
      .sort((a, b) => a.days - b.days);

    return processed;
  };

  const processedLeases = processLeases(leases);

  return (
    <div className="echo-card" style={{ border: 'none' }}>
      <h3 style={{ fontSize: '14px', fontWeight: 600, color: '#0f172a', marginBottom: '2px' }}>Leases nearing expiry</h3>
      <p style={{ fontSize: '12px', color: '#64748b', marginBottom: '16px' }}>Lease expiry status · Sorted by urgency</p>

      {loading ? (
        <div style={{ textAlign: 'center', padding: '20px', color: '#64748b' }}>Loading...</div>
      ) : processedLeases.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '20px', color: '#64748b' }}>No active leases found</div>
      ) : (
        <>
          <div style={{
            display: 'flex',
            flexDirection: 'column',
            gap: '16px',
            maxHeight: '300px',
            overflowY: 'auto',
            paddingRight: '8px'
          }}>
            <style>
              {`
                .lease-expiry-scroll::-webkit-scrollbar {
                  width: 6px;
                }
                .lease-expiry-scroll::-webkit-scrollbar-track {
                  background: #f1f5f9;
                  border-radius: 3px;
                }
                .lease-expiry-scroll::-webkit-scrollbar-thumb {
                  background: #cbd5e1;
                  border-radius: 3px;
                }
                .lease-expiry-scroll::-webkit-scrollbar-thumb:hover {
                  background: #94a3b8;
                }
              `}
            </style>
            {processedLeases.slice(0, 3).map((l, i) => {
              const colorInfo = getExpiryColor(l.days);
              return (
                <div
                  key={i}
                  onClick={() => handleUnitClick(l.unitId) || handleLeaseClick(l.leaseId)}
                  style={{
                    display: 'flex',
                    alignItems: 'flex-start',
                    gap: '12px',
                    cursor: 'pointer',
                    padding: '8px',
                    borderRadius: '6px',
                    transition: 'background-color 0.2s'
                  }}
                  onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#f8fafc'}
                  onMouseLeave={(e) => e.currentTarget.style.backgroundColor = 'transparent'}
                >
                  <span style={{ fontSize: '14px', fontWeight: 700, color: '#2e66ff', minWidth: '60px' }}>{l.unitNumber}</span>
                  <div style={{ flex: 1 }}>
                    <p style={{ fontSize: '14px', color: '#0f172a', margin: 0, fontWeight: 500 }}>{l.brandName}</p>
                    <p style={{ fontSize: '12px', color: '#64748b', margin: 0 }}>{l.area} ·  {l.amount} PM</p>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexShrink: 0 }}>
                    <span style={{ fontSize: '14px', fontWeight: 500, color: colorInfo.text }}>{l.days} days</span>
                    <span style={{
                      fontSize: '12px',
                      padding: '2px 8px',
                      borderRadius: '9999px',
                      fontWeight: 500,
                      backgroundColor: colorInfo.bg,
                      color: colorInfo.text
                    }}>{colorInfo.status}</span>
                  </div>
                </div>
              );
            })}
          </div>
        </>
      )}
    </div>
  );
};

export default LeaseExpirySection;
